import random

def task_func(text, seed=None):
    if not text:
        raise ValueError("Input text is empty")

    if seed is not None:
        random.seed(seed)

    lowercase_letters = string.ascii_lowercase
    digits = string.digits
    result = []

    for char in text:
        if char.isalpha():
            result.append(random.choice(lowercase_letters))
        elif char.isdigit():
            result.append(random.choice(digits))
        elif char == ' ':
            if random.choice([True, False]):
                result.append(random.choice(digits))
            else:
                result.append(random.choice(lowercase_letters))
        else:
            result.append(char)

