import subprocess
import os
import signal
import time

def task_func(process_name: str) -> int:
    try:
        result = subprocess.run(['pgrep', process_name], capture_output=True, text=True, check=False)
        if result.returncode != 0:
            return 0
        pids = [int(pid) for pid in result.stdout.strip().split('\n') if pid.strip()]
        stopped_count = 0
        for pid in pids:
            try:
                os.kill(pid, signal.SIGTERM)
            except ProcessLookupError:
                continue
        time.sleep(1)
        remaining_pids = []
        for pid in pids:
            try:
                os.kill(pid, 0)
                remaining_pids.append(pid)
            except ProcessLookupError:
                stopped_count += 1
        return stopped_count
    except Exception:
        return 0
