    inc = [arr[i] for i in range(n)]
    for i in range(1, n):
        for j in range(i):
            if arr[j] < arr[i]:
                inc[i] = max(inc[i], inc[j] + arr[i])

    # Step 3: Compute max decreasing sum starting at each index
    dec = [arr[i] for i in range(n)]
    for i in range(n-2, -1, -1):
        for j in range(i+1, n):
