def count_rotations(arr):
    n = len(arr)
    if n == 0:
        return 0
    if n == 1:
        return 0

    left, right = 0, n - 1
    while left <= right:
        # If the array is already sorted (no rotation)
        if arr[left] <= arr[right]:
            return left

        mid = (left + right) // 2

        # Check if mid is the pivot (minimum element)
        left_neighbor = arr[(mid - 1) % n]
        right_neighbor = arr[(mid + 1) % n]

        if arr[mid] <= left_neighbor and arr[mid] <= right_neighbor:
            return mid

        # If left half is sorted, pivot must be in the right half
        if arr[left] <= arr[mid]:
            left = mid + 1
        else:
            # Left half is not sorted, so pivot is in the left half
            right = mid - 1

    return 0
