bool isPerfectSquare(int n) {
    if (n < 0) return false;
    if (n == 0 || n == 1) return true;
    long long int left = 1, right = n;
    while (left <= right) {
        long long int mid = left + (right - left) / 2;
        long long int square = mid * mid;
        if (square == n) return true;
        else if (square < n) left = mid + 1;
        else right = mid - 1;
    }
    return false;
