            line_num1 += 1
            line_num2 += 1
        elif status == '-':
            diff_data.append({'Line Number': line_num1, 'Status': '-', 'Content': content})
            line_num1 += 1
        elif status == '+':
            diff_data.append({'Line Number': line_num2, 'Status': '+', 'Content': content})
            line_num2 += 1

