import os
import re
from pathlib import Path

def task_func(dir_path: str, predicates: list) -> dict:
    if not Path(dir_path).exists() or not Path(dir_path).is_dir():
        raise FileNotFoundError(f"Directory not found: {dir_path}")

    if not predicates:
        raise ValueError("No valid predicates provided.")

    items = [item.name for item in Path(dir_path).iterdir()]

    # Deduplicate predicates
    unique_predicates = list(set(predicates))

    result = {}
    for item in items:
        item_results = {}
        for pred in unique_predicates:
            if isinstance(pred, str):
                # Treat string as regex pattern
                item_results[pred] = bool(re.fullmatch(pred, item))
            elif callable(pred):
                # Treat callable as predicate function
                item_results[pred] = pred(item)
            else:
                raise ValueError(f"Invalid predicate: {pred}")
        result[item] = item_results

    return result
