import subprocess
import time
import json
import platform
LOGFILE_PATH = "logfile.log"
def task_func(interval, duration):
    if interval <= 0 or duration <= 0:
        raise ValueError("interval and duration must be greater than zero")

    if platform.system() == "Windows":
        cmd = "wmic cpu get loadpercentage"
    else:
        cmd = "top -bn1 | grep 'Cpu(s)' | awk '{print $2}' | cut -d'%' -f1"

    records = []
    start_time = time.time()
    while (time.time() - start_time) < duration:
        try:
            if platform.system() == "Windows":
                result = subprocess.run(cmd, capture_output=True, text=True, shell=True)
                cpu_usage = float(result.stdout.strip().split('\n')[1])
            else:
                result = subprocess.run(cmd, shell=True, capture_output=True, text=True)
                cpu_usage = float(result.stdout.strip())
        except (subprocess.CalledProcessError, ValueError, IndexError):
            cpu_usage = 0.0

        timestamp = time.time()
        records.append({"timestamp": timestamp, "cpu_usage": cpu_usage})
        time.sleep(interval)

    try:
        with open(LOGFILE_PATH, "w") as f:
            json.dump(records, f)
    except IOError:
        return None

    return LOGFILE_PATH
