import os
import glob
from pathlib import Path
import zipfile

def task_func(source_directory, target_directory, zip_name):
    source_path = Path(source_directory)
    target_path = Path(target_directory)

    if not source_path.exists():
        raise OSError(f"Source directory does not exist: {source_directory}")

    if not target_path.exists():
        target_path.mkdir(parents=True, exist_ok=True)

    valid_extensions = {'.txt', '.docx', '.xlsx', '.csv'}
    zip_file_path = target_path / f"{zip_name}.zip"

    with zipfile.ZipFile(zip_file_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for ext in valid_extensions:
            pattern = f"{source_path}/**/*{ext}"
            for file_path in glob.glob(pattern, recursive=True):
                if os.path.isfile(file_path):
                    arcname = Path(file_path).relative_to(source_path)
                    zipf.write(file_path, arcname=arcname)

    return str(zip_file_path.resolve())
