import pandas as pd
from random import randint, seed

def task_func(dictionary, item, sample_size=None, random_seed=None):
    df = pd.DataFrame.from_dict(dictionary, orient='index')
    positions = []
    for row_idx in df.index:
        for col_name in df.columns:
            if df.loc[row_idx, col_name] == item:
                positions.append((row_idx, col_name))
    if random_seed is not None:
        seed(random_seed)
    if sample_size is not None:
        sample_size = min(sample_size, len(positions))
        sampled_positions = [positions[randint(0, len(positions) - 1)] for _ in range(sample_size)]
        return (sampled_positions, df)
    return (positions, df)
