import numpy as np
from scipy import stats

# Constants
FEATURES = ['feature1', 'feature2', 'feature3', 'feature4', 'feature5']

def task_func(df, dct):
    try:
        if df is None or not isinstance(df, type(pd.DataFrame())) or not all(feature in df.columns for feature in FEATURES):
            return "Invalid input"
        if not isinstance(dct, dict) or len(dct) == 0:
            return "Invalid input"

        df = df.replace(dct)

        result = {}
        for feature in FEATURES:
            values = df[feature].dropna().values
            if len(values) == 0:
                return "Invalid input"
            mean_val = np.mean(values)
            median_val = np.median(values)
            mode_val = stats.mode(values, keepdims=True).mode[0]
            var_val = np.var(values, ddof=1) if len(values) > 1 else 0
            result[feature] = {
                'mean': mean_val,
                'median': median_val,
                'mode': mode_val,
                'variance': var_val
            }

        return result
    except Exception:
        return "Invalid input"
