import collections
import numpy as np
def task_func(file_name):
    try:
        df = np.genfromtxt(file_name, delimiter=',', dtype=str, encoding='utf-8', skip_header=1)
        if df.size == 0:
            return {}

        header = np.genfromtxt(file_name, delimiter=',', dtype=str, encoding='utf-8', max_rows=1)
        result = {}

        for i, col_name in enumerate(header):
            column_values = df[:, i]
            if len(column_values) == 0:
                result[col_name] = None
            else:
                counter = collections.Counter(column_values)
                max_count = max(counter.values())
                most_common_values = [val for val, count in counter.items() if count == max_count]
                most_common_values.sort()
                result[col_name] = most_common_values[0]

        return result
    except Exception:
        return {}
