import pandas as pd
import json
import os
import math

def task_func(json_data, output_dir=".", file_name="country_population_report.csv"):
    if not json_data:
        raise ValueError("JSON data is empty")

    try:
        data = json.loads(json_data)
    except json.JSONDecodeError:
        raise ValueError("JSON data is malformed")

    if not isinstance(data, list):
        raise ValueError("JSON data must be a list of country-population records")

    country_population_list = []
    for item in data:
        if not isinstance(item, dict):
            raise ValueError("Each record must be a dictionary")
        if "Country" not in item or "Population" not in item:
            raise ValueError("Each record must contain 'Country' and 'Population' keys")
        country = item["Country"]
        population = item["Population"]
        if not isinstance(country, str):
            raise ValueError("Country name must be a string")
        if not isinstance(population, (int, float)):
            raise ValueError("Population must be a number")
        if population < 0:
            raise ValueError("Population cannot be negative")
        population = int(math.floor(population))
        country_population_list.append({"Country": country, "Population": population})

    df = pd.DataFrame(country_population_list)

    if not os.path.exists(output_dir):
        try:
            os.makedirs(output_dir)
        except OSError:
            raise IOError(f"Could not create directory: {output_dir}")

    file_path = os.path.join(output_dir, file_name)
    try:
        df.to_csv(file_path, index=False)
    except IOError:
        raise IOError(f"Could not write file to: {file_path}")

    return file_path, df
