import re
import socket

def task_func(ip_addresses: list) -> dict:
    result = {}
    ip_pattern = re.compile(r'^(\d{1,3}\.){3}\d{1,3}$')

    for ip in ip_addresses:
        if ip_pattern.match(ip):
            try:
                hostname = socket.gethostbyaddr(ip)[0]
                result[ip] = hostname
            except (socket.herror, socket.gaierror):
                result[ip] = None
        else:
            result[ip] = None
    return result
